function Counter() {
  const [count, setCount] = useState(0);

  return (
    <div>
      <h1>카운터: {count}</h1>
      <button onClick={() => setCount(count + 1)}>
        +1
      </button>
    </div>
  );
}

export default Counter;`,codeLang:"tsx"},{id:"vite-setup",title:"Vite 프로젝트 설정",icon:"⚡",description:"Vite를 사용한 빠른 React 프로젝트 생성, TypeScript 설정, 환경변수 관리, 빌드 최적화를 학습합니다.",content:[{subtitle:"Vite란?",text:"Vite는 차세대 프론트엔드 빌드 도구로, ESM(ES Modules) 기반의 초고속 개발 서버와 Rollup 기반의 최적화된 빌드를 제공합니다."},{subtitle:"주요 장점",items:["번들링 없는 즉각적인 서버 시작","HMR(Hot Module Replacement) 지원","TypeScript, JSX, CSS 기본 지원","환경변수(.env) 자동 로드 (VITE_ 접두사)"]},{subtitle:"프로젝트 구조",items:["index.html: SPA 진입점","src/main.tsx: React 앱 마운트","src/App.tsx: 라우팅 및 레이아웃","vite.config.ts: 빌드 설정"]}],code:`// vite.config.ts
